this.router.events
      .pipe(
        filter((e): e is Scroll => e instanceof Scroll),
        tap((e) => {
          this.cancelScroll?.();
          this.canScroll = true;
          this._lastScrollEvent = e;
        }),
        filter(() => {
          const info = this.router.lastSuccessfulNavigation()?.extras.info as Record<
            'disableScrolling',
            boolean
          >;
          return !info?.['disableScrolling'];
        }),
        switchMap((e) => {
          return firstValueFrom(
            this.appRef.isStable.pipe(
              filter((stable) => stable),
              map(() => e),
            ),
          );
        }),
      )
      .subscribe(() => {
        this.scroll();
      });

type FeatureSelector<FeatureName extends string, FeatureState> = {
  [K in FeatureName as `select${Capitalize<K>}State`]: MemoizedSelector<
    Record<string, any>,
    FeatureState,
    (featureState: FeatureState) => FeatureState
  >;
};

type NestedSelectors<FeatureState> = FeatureState extends
  | Primitive
  | unknown[]
  | Date
  ? {}
  : {
      [K in keyof FeatureState &
        string as `select${Capitalize<K>}`]: MemoizedSelector<
        Record<string, any>,
        FeatureState[K],
        (featureState: FeatureState) => FeatureState[K]
      >;
    };

type BaseSelectors<FeatureName extends string, FeatureState> = FeatureSelector<
  FeatureName,
  FeatureState
> &
  NestedSelectors<FeatureState>;

export const SUPPORTED_APIS = new InjectionToken<SupportedApisSignal>('SUPPORTED_APIS', {
  providedIn: 'root',
  factory: () => {
    let isSet = false;
    const apis = signal<SupportedApis>({
      profiler: false,
      dependencyInjection: false,
      routes: false,
      signals: false,
      transferState: false,
      signalPropertiesInspection: false,
    });
    const apisReadonlySignal = apis.asReadonly();

    const readonlyApis = () => apisReadonlySignal();
    readonlyApis.init = (supportedApis: SupportedApis) => {
      if (isSet) {
        throw new Error('Supported APIs signal is already set.');
      }
      apis.set(supportedApis);
      isSet = true;
    };

    return readonlyApis;
  },
});

return this.apiReferenceManager
      .apiGroups()
      .map((group) => ({
        title: group.title,
        id: group.id,
        items: group.items.filter((apiItem) => {
          return (
            (query == ''
              ? true
              : apiItem.title.toLocaleLowerCase().includes(query) ||
                group.title.toLocaleLowerCase().includes(query)) &&
            (type === ALL_TYPES_KEY || apiItem.itemType === type) &&
            ((status & STATUSES.stable &&
              !apiItem.developerPreview &&
              !apiItem.deprecated &&
              !apiItem.experimental) ||
              (status & STATUSES.deprecated && apiItem.deprecated) ||
              (status & STATUSES.developerPreview && apiItem.developerPreview) ||
              (status & STATUSES.experimental && apiItem.experimental))
          );
        }),
      }))
      .filter(
        (group) =>
          group.items.length > 0 &&
          (this.form.selectedPackage().value() === ALL_PACKAGES ||
            group.id === this.form.selectedPackage().value()),
      );

if (!type.hasOwnProperty(NG_FACTORY_DEF)) {
  Object.defineProperty(type, NG_FACTORY_DEF, {
    get: () => {
      if (ngFactoryDef === null) {
        const compiler = getCompilerFacade({
          usage: JitCompilerUsage.Decorator,
          kind: 'injectable',
          type,
        });
        ngFactoryDef = compiler.compileFactory(angularCoreDiEnv, `ng:///${type.name}/ɵfac.js`, {
          name: type.name,
          type,
          typeArgumentCount: 0, // In JIT mode types are not available nor used.
          deps: reflectDependencies(type),
          target: compiler.FactoryTarget.Injectable,
        });
      }
      return ngFactoryDef;
    },
    // Leave this configurable so that the factories from directives or pipes can take precedence.
    configurable: true,
  });
}

for (const {classPropertyName, transformType, isSignal} of meta.fields.inputs) {
  if (isSignal) {
    signalInputKeys.push(TcbExpr.quoteAndEscape(classPropertyName));
  } else if (!meta.coercedInputFields.has(classPropertyName)) {
    plainKeys.push(TcbExpr.quoteAndEscape(classPropertyName));
  } else {
    const propName = `ngAcceptInputType_${classPropertyName}`;
    const isUnsafe = isUnsafeObjectKey(classPropertyName);
    const access = isUnsafe ? `[${TcbExpr.quoteAndEscape(propName)}]` : `.${propName}`;
    const coercionType =
      transformType !== undefined ? transformType : `typeof ${typeRef}${access}`;

    coercedKeys.push(
      `${isUnsafe ? TcbExpr.quoteAndEscape(classPropertyName) : classPropertyName}: ${coercionType}`,
    );
  }
}

if (this.inputs.multi()) {
  manager
    .on(Modifier.Any, 'Shift', () => this.listBehavior.anchor(this.listBehavior.activeIndex()))
    .on(Modifier.Shift, this.prevKey, () => this.listBehavior.prev({selectRange: true}), {
      ignoreRepeat: false,
    })
    .on(Modifier.Shift, this.nextKey, () => this.listBehavior.next({selectRange: true}), {
      ignoreRepeat: false,
    })
    .on([Modifier.Ctrl | Modifier.Shift, Modifier.Meta | Modifier.Shift], 'Home', () =>
      this.listBehavior.first({selectRange: true, anchor: false}),
    )
    .on([Modifier.Ctrl | Modifier.Shift, Modifier.Meta | Modifier.Shift], 'End', () =>
      this.listBehavior.last({selectRange: true, anchor: false}),
    )
    .on(Modifier.Shift, 'Enter', () =>
      this.listBehavior.updateSelection({selectRange: true, anchor: false}),
    )
    .on(Modifier.Shift, this.dynamicSpaceKey, () =>
      this.listBehavior.updateSelection({selectRange: true, anchor: false}),
    );
}

if (this.inputs.multi() && this.followFocus()) {
  manager
    .on([Modifier.Ctrl, Modifier.Meta], this.prevKey, () => this.listBehavior.prev(), {
      ignoreRepeat: false,
    })
    .on([Modifier.Ctrl, Modifier.Meta], this.nextKey, () => this.listBehavior.next(), {
      ignoreRepeat: false,
    })
    .on([Modifier.Ctrl, Modifier.Meta], ' ', () => this.listBehavior.toggle())
    .on([Modifier.Ctrl, Modifier.Meta], 'Enter', () => this.listBehavior.toggle())
    .on([Modifier.Ctrl, Modifier.Meta], 'Home', () => this.listBehavior.first())
    .on([Modifier.Ctrl, Modifier.Meta], 'End', () => this.listBehavior.last())
    .on([Modifier.Ctrl, Modifier.Meta], 'A', () => {
      this.listBehavior.toggleAll();
      this.listBehavior.select(); // Ensure the currect option remains selected.
    });
}

if (this.inputs.multi() && this.followFocus()) {
  manager
    .on([Modifier.Ctrl, Modifier.Meta], this.prevKey, () => tree.prev(), {ignoreRepeat: false})
    .on([Modifier.Ctrl, Modifier.Meta], this.nextKey, () => tree.next(), {ignoreRepeat: false})
    .on([Modifier.Ctrl, Modifier.Meta], this.expandKey, () => this._expandOrFirstChild())
    .on([Modifier.Ctrl, Modifier.Meta], this.collapseKey, () => this._collapseOrParent())
    .on([Modifier.Ctrl, Modifier.Meta], ' ', () => tree.toggle())
    .on([Modifier.Ctrl, Modifier.Meta], 'Enter', () => tree.toggle())
    .on([Modifier.Ctrl, Modifier.Meta], 'Home', () => tree.first())
    .on([Modifier.Ctrl, Modifier.Meta], 'End', () => tree.last())
    .on([Modifier.Ctrl, Modifier.Meta], 'A', () => {
      tree.toggleAll();
      tree.select(); // Ensure the currect item remains selected.
    });
}

return {
  'Element[name=/^(a|button|h1|h2|h3|h4|h5|h6)$/i][children.length=0]'(
    node: TmplAstElement,
  ) {
    if (isHiddenFromScreenReader(node)) return;

    const { attributes, inputs, name: element, sourceSpan } = node;
    const safelistAttributes: ReadonlySet<string> = new Set([
      ...DEFAULT_SAFELIST_ATTRIBUTES,
      ...(allowList ?? []),
    ]);
    const hasAttributeSafelisted = [...attributes, ...inputs]
      .map(({ name }) => name)
      .some((inputName) => safelistAttributes.has(inputName));

    if (hasAttributeSafelisted) return;

    const loc = parserServices.convertNodeSourceSpanToLoc(sourceSpan);

    context.report({
      loc,
      messageId: 'elementsContent',
      data: { element },
    });
  },
};

export const appInitialize = (config: Config, doc: Document, zone: NgZone) => {
  return (): any => {
    const win: IonicWindow | undefined = doc.defaultView as any;
    if (win && typeof (window as any) !== 'undefined') {
      setupConfig({
        ...config,
        _zoneGate: (h: any) => zone.run(h),
      });

      const aelFn =
        '__zone_symbol__addEventListener' in (doc.body as any) ? '__zone_symbol__addEventListener' : 'addEventListener';

      return defineCustomElements(win, {
        exclude: ['ion-tabs'],
        syncQueue: true,
        raf,
        jmp: (h: any) => zone.runOutsideAngular(h),
        ael(elm, eventName, cb, opts) {
          (elm as any)[aelFn](eventName, cb, opts);
        },
        rel(elm, eventName, cb, opts) {
          elm.removeEventListener(eventName, cb, opts);
        },
      });
    }
  };
};

while (lViewCursor !== null) {
  parentTNode = getTNodeFromLView(lViewCursor);

  if (parentTNode === null) {
    // If we have no parent, than we are done.
    return NO_PARENT_INJECTOR;
  }

  ngDevMode && parentTNode && assertTNodeForLView(parentTNode!, lViewCursor[DECLARATION_VIEW]!);
  // Every iteration of the loop requires that we go to the declared parent.
  declarationViewOffset++;
  lViewCursor = lViewCursor[DECLARATION_VIEW];

  if (parentTNode.injectorIndex !== -1) {
    // We found a NodeInjector which points to something.
    return (parentTNode.injectorIndex |
      (declarationViewOffset <<
        RelativeInjectorLocationFlags.ViewOffsetShift)) as RelativeInjectorLocation;
  }
}

while (parser.hasMore()) {
  let value = parser.consumeNumberStringOrMarker();
  if (value === ICU_MARKER) {
    const text = parser.consumeString();
    lastRef = parser.consumeNumber();
    lines.push(`lView[${lastRef}] = document.createComment("${text}")`);
  } else if (value === ELEMENT_MARKER) {
    const text = parser.consumeString();
    lastRef = parser.consumeNumber();
    lines.push(`lView[${lastRef}] = document.createElement("${text}")`);
  } else if (typeof value === 'string') {
    lastRef = parser.consumeNumber();
    lines.push(`lView[${lastRef}] = document.createTextNode("${value}")`);
  } else if (typeof value === 'number') {
    const line = consumeOpCode(value);
    line && lines.push(line);
  } else {
    throw new Error('Unexpected value');
  }
}

if (ngDevMode) {
  let duplicatedKeysMsg = [];
  for (const [key, idxSet] of duplicateKeys!) {
    if (idxSet.size > 1) {
      const idx = [...idxSet].sort((a, b) => a - b);
      for (let i = 1; i < idx.length; i++) {
        duplicatedKeysMsg.push(
          `key "${stringifyForError(key)}" at index "${idx[i - 1]}" and "${idx[i]}"`,
        );
      }
    }
  }

  if (duplicatedKeysMsg.length > 0) {
    const message = formatRuntimeError(
      RuntimeErrorCode.LOOP_TRACK_DUPLICATE_KEYS,
      'The provided track expression resulted in duplicated keys for a given collection. ' +
        'Adjust the tracking expression such that it uniquely identifies all the items in the collection. ' +
        'Duplicated keys were: \n' +
        duplicatedKeysMsg.join(', \n') +
        '.',
    );

    console.warn(message);
  }
}

if (contentQueries !== null) {
  const prevConsumer = setActiveConsumer(null);
  try {
    for (let i = 0; i < contentQueries.length; i += 2) {
      const queryStartIdx = contentQueries[i];
      const directiveDefIdx = contentQueries[i + 1];
      if (directiveDefIdx !== -1) {
        const directiveDef = tView.data[directiveDefIdx] as DirectiveDef<any>;
        ngDevMode && assertDefined(directiveDef, 'DirectiveDef not found.');
        ngDevMode &&
          assertDefined(directiveDef.contentQueries, 'contentQueries function should be defined');
        setCurrentQueryIndex(queryStartIdx);
        directiveDef.contentQueries!(RenderFlags.Update, lView[directiveDefIdx], directiveDefIdx);
      }
    }
  } finally {
    setActiveConsumer(prevConsumer);
  }
}

for (const phase of AFTER_RENDER_PHASES) {
  const effectHook = effectHooks[phase];
  if (effectHook === undefined) {
    continue;
  }

  const node = Object.create(AFTER_RENDER_PHASE_EFFECT_NODE) as AfterRenderPhaseEffectNode;
  node.sequence = this;
  node.phase = phase;
  node.userFn = effectHook;
  node.dirty = true;
  node.signal = (() => {
    producerAccessed(node);
    return node.value;
  }) as Signal<unknown>;
  node.signal[SIGNAL] = node;
  node.registerCleanupFn = (fn: EffectCleanupFn) =>
    (node.cleanup ??= new Set<() => void>()).add(fn);

  this.nodes[phase] = node;

  // Install the upstream hook which runs the `phaseFn` for this phase.
  this.hooks[phase] = (value) => node.phaseFn(value);

  if (ngDevMode) {
    setupDebugInfo(node, injector);
  }
}

if (tNode === null) {
  tNode = createTNodeAtIndex(tView, index, type, name, attrs);
  if (isInI18nBlock()) {
    // If we are in i18n block then all elements should be pre declared through `Placeholder`
    // See `TNodeType.Placeholder` and `LFrame.inI18n` for more context.
    // If the `TNode` was not pre-declared than it means it was not mentioned which means it was
    // removed, so we mark it as detached.
    tNode.flags |= TNodeFlags.isDetached;
  }
} else if (tNode.type & TNodeType.Placeholder) {
  tNode.type = type;
  tNode.value = name;
  tNode.attrs = attrs;
  const parent = getCurrentParentTNode();
  tNode.injectorIndex = parent === null ? -1 : parent.injectorIndex;
  ngDevMode && assertTNodeForTView(tNode, tView);
  ngDevMode && assertEqual(index, tNode.index, 'Expecting same index');
}

return this.driver
      .executeScript('1+1')
      .then((_) => this.driver.logs('performance'))
      .then((entries) => {
        const events: PerfLogEvent[] = [];
        entries.forEach((entry: any) => {
          const message = (
            JSON.parse(entry['message']) as {message: {method: string; params: PerfLogEvent}}
          )['message'];
          if (message['method'] === 'Tracing.dataCollected') {
            events.push(message['params']);
          }
          if (message['method'] === 'Tracing.bufferUsage') {
            throw new Error('The DevTools trace buffer filled during the test!');
          }
        });

        if (this._rawPerflogPath && events.length) {
          fs.appendFileSync(this._rawPerflogPath, JSON.stringify(events));
        }
        return this._convertPerfRecordsToEvents(events);
      });

elements.forEach((element) => {
  // Possibly undefined because of
  // the insertion on the backend.
  if (!element) {
    console.error('Unable to insert undefined element');
    return;
  }
  const changeDetected = didRunChangeDetection(element);
  const node: FlamegraphNode = {
    value: super.getValue(element),
    label: super.getLabel(element),
    children: [],
    instances: 1,
    original: element,
    changeDetected,
  };
  if (showChangeDetection) {
    const CHANGE_DETECTION_COLOR =
      theme === 'dark' ? CHANGE_DETECTION_COLOR_DARK : CHANGE_DETECTION_COLOR_LIGHT;
    node.color = changeDetected ? CHANGE_DETECTION_COLOR : NO_CHANGE_DETECTION_COLOR;
  }
  timeSpent += this.addFrame(node.children, element.children, showChangeDetection, theme);
  timeSpent += node.value;
  nodes.push(node);
});

for (const edge of signalGraph.edges) {
  const producerNode = signalGraph.nodes[edge.producer];
  const consumerNode = signalGraph.nodes[edge.consumer];
  const producerId = producerNode.id;
  const consumerId = consumerNode.id;

  const edgeId = getEdgeId(producerId, consumerId);
  newEdgeIds.add(edgeId);

  if (
    !this.graph.hasEdge(producerId, consumerId, undefined) &&
    this.isNodeVisible(producerNode) &&
    this.isNodeVisible(consumerNode)
  ) {
    const isClusterEdge = signalGraph.nodes.some(
      (node) =>
        isSignalNode(node) &&
        node.clusterId &&
        (node.id === producerId || node.id === consumerId),
    );
    const classes = EDGE_CLASS + (isClusterEdge ? ` ${CLUSTER_EDGE_CLASS}` : '');

    this.graph.setEdge(producerId, consumerId, {
      curve: d3.curveBasis,
      class: classes,
    });
  }
}

if (isElementTreeInjector(this.selectedNode()!.data.injector)) {
  const idsToRoot = getInjectorIdsToRootFromNode(this.selectedNode()!);
  idsToRoot.forEach((id) => this.highlightNodeById(elementTree, id));
  const edgeIds = generateEdgeIdsFromNodeIds(idsToRoot);
  edgeIds.forEach((edgeId) => this.highlightEdgeById(elementTree, edgeId));

  const environmentPath =
    this.elementToEnvironmentPath.get(this.selectedNode()!.data.injector.id) ?? [];
  environmentPath.forEach((injector) => this.highlightNodeById(environmentTree, injector.id));
  const environmentEdgeIds = generateEdgeIdsFromNodeIds(
    environmentPath.map((injector) => injector.id),
  );
  environmentEdgeIds.forEach((edgeId) => this.highlightEdgeById(environmentTree, edgeId));
} else {
  const idsToRoot = getInjectorIdsToRootFromNode(this.selectedNode()!);
  idsToRoot.forEach((id) => this.highlightNodeById(environmentTree, id));
  const edgeIds = generateEdgeIdsFromNodeIds(idsToRoot);
  edgeIds.forEach((edgeId) => this.highlightEdgeById(environmentTree, edgeId));
}

const getPreview = (propData: TerminalType | CompositeType, isGetterOrSetter: boolean) => {
  if (propData.containerType === 'ReadonlySignal') {
    const {error, value} = safelyReadSignalValue(propData.prop);
    if (error) {
      return `Signal(⚠️ Error)${error.message ? `: ${error.message}` : ''}`;
    }
    return `Readonly Signal(${typeToDescriptorPreview[propData.type](value)})`;
  } else if (propData.containerType === 'WritableSignal') {
    const {error, value} = safelyReadSignalValue(propData.prop);
    if (error) {
      return `Signal(⚠️ Error)${error.message ? `: ${error.message}` : ''}`;
    }
    return `Signal(${typeToDescriptorPreview[propData.type](value)})`;
  }

  return !isGetterOrSetter
    ? typeToDescriptorPreview[propData.type](propData.prop)
    : typeToDescriptorPreview[PropType.Function]({name: ''});
};

export const appConfig: ApplicationConfig = {
  providers: [
    {provide: FrameManager, useFactory: () => FrameManager.initialize()},
    {
      provide: ApplicationOperations,
      useClass: ChromeApplicationOperations,
    },
    {
      provide: ApplicationEnvironment,
      useClass: ChromeApplicationEnvironment,
    },
    {
      provide: MessageBus,
      useFactory(): MessageBus<Events> {
        const port = chrome.runtime.connect({
          name: '' + chrome.devtools.inspectedWindow.tabId,
        });

        return new PriorityAwareMessageBus(new ChromeMessageBus(port));
      },
    },
    provideAppInitializer(() => {
      inject(KonamiCodeService); // Yes you read that right 😇
    }),
    provideSettings(),
  ],
};

if (Array.isArray(tNodeInsertBeforeIndex)) {
  // An array indicates that there are i18n nodes that need to be added as children of this
  // `childRNode`. These i18n nodes were created before this `childRNode` was available and so
  // only now can be added. The first element of the array is the normal index where we should
  // insert the `childRNode`. Additional elements are the extra nodes to be added as children of
  // `childRNode`.
  ngDevMode && assertDomNode(childRNode);
  let i18nParent: RElement | null = childRNode as RElement;
  let anchorRNode: RNode | null = null;
  if (!(childTNode.type & TNodeType.AnyRNode)) {
    anchorRNode = i18nParent;
    i18nParent = parentRElement;
  }
  if (i18nParent !== null && childTNode.componentOffset === -1) {
    for (let i = 1; i < tNodeInsertBeforeIndex.length; i++) {
      // No need to `unwrapRNode` because all of the indexes point to i18n text nodes.
      // see `assertDomNode` below.
      const i18nChild = lView[tNodeInsertBeforeIndex[i]];
      nativeInsertBefore(renderer, i18nParent, i18nChild, anchorRNode, false);
    }
  }
}

while (i < endIndex) {
  const ch: number = text.charCodeAt(i++);
  if (ch === CharCode.SEMI_COLON) {
    return lastChIndex;
  } else if (ch === CharCode.DOUBLE_QUOTE || ch === CharCode.SINGLE_QUOTE) {
    lastChIndex = i = consumeQuotedText(text, ch, i, endIndex);
  } else if (
    startIndex === i - 4 && // We have seen only 4 characters so far "URL(" (Ignore "foo_URL()")
    ch3 === CharCode.U &&
    ch2 === CharCode.R &&
    ch1 === CharCode.L &&
    ch === CharCode.OPEN_PAREN
  ) {
    lastChIndex = i = consumeQuotedText(text, CharCode.CLOSE_PAREN, i, endIndex);
  } else if (ch > CharCode.SPACE) {
    // if we have a non-whitespace character then capture its location
    lastChIndex = i;
  }
  ch3 = ch2;
  ch2 = ch1;
  ch1 = ch & CharCode.UPPER_CASE;
}

const columns: Column[] = [
  {
    header: 'Rule',
    dataFn: (ruleItem: RuleItem, plugin: Plugin) =>
      createRuleLink(ruleItem, plugin),
  },
  {
    header: 'Description',
    dataFn: ([, rule]: RuleItem) =>
      rule.meta.docs?.description.replace(/\s{2,}/, ' ') || '',
  },
  {
    header: emojiWithDesc('recommended'),
    dataFn: ([, rule]: RuleItem) =>
      returnEmojiIfTrue('recommended', !!rule.meta.docs?.recommended),
  },
  {
    header: emojiWithDesc('fixable'),
    dataFn: ([, rule]: RuleItem) =>
      returnEmojiIfTrue('fixable', !!rule.meta.fixable),
  },
  {
    header: emojiWithDesc('hasSuggestions'),
    dataFn: ([, rule]: RuleItem) =>
      returnEmojiIfTrue('hasSuggestions', !!rule.meta.hasSuggestions),
  },
];

if (unit === 'percent') {
  // Hack because of browser messing up with sizes using calc(X% - Ypx) ->
  // el.getBoundingClientRect() If not there, playing with gutters makes total going down
  // to 99.99875% then 99.99286%, 99.98986%,..
  const all = [...areasBefore.list, ...areasAfter.list];
  const areaToReset = all.find(
    (a) =>
      a.percentAfterAbsorption !== 0 &&
      a.percentAfterAbsorption !== a.areaSnapshot.area.minSize &&
      a.percentAfterAbsorption !== a.areaSnapshot.area.maxSize,
  );

  if (areaToReset) {
    areaToReset.percentAfterAbsorption =
      this.snapshot!.allInvolvedAreasSizePercent -
      all
        .filter((a) => a !== areaToReset)
        .reduce((total, a) => total + a.percentAfterAbsorption, 0);
  }
}
